import React, { useState } from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import timeGridPlugin from '@fullcalendar/timegrid';
import interactionPlugin from '@fullcalendar/interaction';
import "../../config/index.css";

const ScheduleCalendar = ({ schedules }) => {
    const [selectedEvent, setSelectedEvent] = useState(null);

    const events = schedules.map((schedule) => ({
        id: schedule.id,  // ID를 추가하여 이벤트를 구분할 수 있게 함
        title: schedule.name,
        start: schedule.startDateTime,
        end: schedule.endDateTime,
        extendedProps: {
            scheduleInfo: schedule.scheduleInfo,
            scheduleType: schedule.scheduleType,
            institutionId: schedule.institutionId,
        },
    }));

    const handleEventClick = (info) => {
        const eventDetails = {
            id: info.event.id,
            title: info.event.title,
            scheduleInfo: info.event.extendedProps.scheduleInfo,
            start: info.event.start ? info.event.start.toLocaleDateString() : '-',
            startTime: info.event.start
                ? info.event.start.toLocaleTimeString('ko-KR')
                : '-',
            end: info.event.end ? info.event.end.toLocaleDateString() : '-',
            endTime: info.event.end
                ? info.event.end.toLocaleTimeString('-')
                : '-',
            scheduleType: info.event.extendedProps.scheduleType,
            institutionId2: info.event.extendedProps.institutionId,
        };

        setSelectedEvent(eventDetails);

        // 새 창을 열고, 모달 내용을 새 창에 표시
        const newWindow = window.open('', '_blank', 'width=600,height=400,left=200,top=200'); // 크기와 위치 지정
        newWindow.document.write(`
            <html>
                <head><title>상세 일정</title></head>
                <body>
                    <h2>상세 일정</h2>
                    <p><strong>이름:</strong> ${eventDetails.title}</p>
                    <p><strong>일정 정보:</strong> ${eventDetails.scheduleInfo}</p>
                    <p><strong>기간:</strong> ${eventDetails.start} ~ ${eventDetails.end}</p>
                    <p><strong>시간:</strong> ${eventDetails.startTime} ~ ${eventDetails.endTime}</p>
                     <button 
                    id="editBtn"
                    style="
                    padding: 12px; 
                    background-color: #007bff; 
                    color: white; 
                    border: none; 
                    border-radius: 4px; 
                    font-size: 16px; 
                    cursor: pointer; 
                    font-weight: bold; 
                    transition: background-color 0.3s ease; 
                    margin: 10px 10px; 
                    text-align: center; 
                    float: right; 
                    flex-shrink: 0;" >수정</button>
                    <button 
                    style="
                    padding: 12px; 
                    background-color: #4caf50; 
                    color: white; 
                    border: none; 
                    border-radius: 4px; 
                    font-size: 16px; 
                    cursor: pointer; 
                    font-weight: bold; 
                    transition: background-color 0.3s ease; 
                    margin: 10px 10px; 
                    text-align: center; 
                    float: right; 
                    flex-shrink: 0;"
                    onclick="window.close()" >닫기</button>
                    <script>
                        document.getElementById('editBtn').addEventListener('click', function() {
                            const editUrl = 
                            '/personnel/institution/${eventDetails.institutionId2}/schedule/${eventDetails.id}'; 
                            // 수정 페이지 URL
                            window.opener.location.href = editUrl; // 부모 창의 URL 변경
                            window.close(); // 현재 창 닫기
                        });
                    </script>
                </body>
            </html>
        `);
    };

    return (
        <div>
            <h3>Schedules</h3>
            <FullCalendar
                plugins={[dayGridPlugin, timeGridPlugin, interactionPlugin]}
                initialView="dayGridMonth"
                headerToolbar={{
                    left: 'prev,next today',
                    center: 'title',
                    right: '',
                }}
                events={events}
                eventClick={handleEventClick}  // 클릭 이벤트 처리기 등록
            />
        </div>
    );
};

export default ScheduleCalendar;
